#!/usr/bin/env python3
import ast
import sys

# Verify that the gradient_noise.py file has valid Python syntax and the correct structure
with open('/workspace/torch/optim/gradient_noise.py', 'r') as f:
    code = f.read()

try:
    tree = ast.parse(code)
    print("✓ gradient_noise.py has valid Python syntax")
except SyntaxError as e:
    print(f"✗ Syntax error in gradient_noise.py: {e}")
    sys.exit(1)

# Find the GradientNoiseInjector class
class_found = False
methods_found = {}
for node in ast.walk(tree):
    if isinstance(node, ast.ClassDef) and node.name == 'GradientNoiseInjector':
        class_found = True
        for item in node.body:
            if isinstance(item, ast.FunctionDef):
                methods_found[item.name] = True

if not class_found:
    print("✗ GradientNoiseInjector class not found")
    sys.exit(1)

print("✓ GradientNoiseInjector class found")

required_methods = ['__init__', 'step', 'zero_grad', 'state_dict', 'load_state_dict', '_inject_noise', '_compute_sigma']
for method in required_methods:
    if method in methods_found:
        print(f"✓ Method {method} found")
    else:
        print(f"✗ Method {method} not found")
        sys.exit(1)

print("\n✓ All required methods are present")
print("✓ Implementation structure is correct")

# Check __init__.py
with open('/workspace/torch/optim/__init__.py', 'r') as f:
    init_code = f.read()

if 'GradientNoiseInjector' in init_code:
    print("✓ GradientNoiseInjector is imported in __init__.py")
else:
    print("✗ GradientNoiseInjector is not imported in __init__.py")
    sys.exit(1)

if 'GradientNoiseInjector' in init_code.split('__all__')[1]:
    print("✓ GradientNoiseInjector is in __all__")
else:
    print("✗ GradientNoiseInjector is not in __all__")
    sys.exit(1)

print("\n✓ __init__.py is correctly configured")
EOF
python3 /tmp/verify_syntax.py

